18	ciphertext_t public_key_t::encrypt(mem_t plain, mem_t label, const bn_t& r, const bn_t& s, mem_t iv) const {
19	  ciphertext_t ciphertext;
20	  const auto& G = Q.get_curve().generator();
21	  const mod_t& q = Q.get_curve().order();
22	
23	  ecc_point_t P = r * Q;
24	  buf_t key;
25	
26	  key = ro::hash_string(P).bitlen(aes_bits);
27	  ciphertext.iv = iv;
28	  aes_gcm_t::encrypt(key, ciphertext.iv, label, tag_size, plain, ciphertext.c);
29	
30	  ciphertext.R1 = r * G;
31	  ecc_point_t W1 = s * G;
32	  ciphertext.R2 = r * Gamma;
33	  ecc_point_t W2 = s * Gamma;
34	
35	  ciphertext.e = ro::hash_number(ciphertext.c, label, ciphertext.R1, W1, ciphertext.R2, W2, iv).mod(q);
36	  MODULO(q) ciphertext.f = s + r * ciphertext.e;
37	
38	  ciphertext.L = label;
39	
40	  return ciphertext;
41	}
