94	error_t ciphertext_t::decrypt(const ecc_point_t& V, buf_t& dec, mem_t label) const {
95	  error_t rv = UNINITIALIZED_ERROR;
96	  buf_t key;
97	  ecurve_t curve = V.get_curve();
98	
99	  key = ro::hash_string(V).bitlen(aes_bits);
100	  if (rv = aes_gcm_t::decrypt(key, iv, label, tag_size, c, dec)) return rv;
